    const ctx = await browser.newContext({ viewport: { width: vp.width, height: vp.height } });
    const page = await ctx.newPage();
    const errors = [];
    const failedRequests = [];

    page.on('console', msg => { if (msg.type() === 'error') errors.push(msg.text()); });
    page.on('requestfailed', req => { failedRequests.push(req.url()); });

    try {
      await page.goto(BASE, { waitUntil: 'networkidle', timeout: 30000 });
      await page.waitForTimeout(2000);

      const scrollWidth = await page.evaluate(() => document.documentElement.scrollWidth);
      const clientWidth = await page.evaluate(() => document.documentElement.clientWidth);
      const hasOverflow = scrollWidth > clientWidth + 2;

      const sections = await page.evaluate(() => {
        const ids = ['properties', 'reels', 'how-it-works', 'trust', 'partners'];
        return ids.filter(id => { const el = document.getElementById(id); return el && el.offsetHeight > 0; });
      });

      const reelsCount = await page.evaluate(() => {
        const el = document.getElementById('reels');
        if (!el) return 0;
        return el.querySelectorAll('[class*="reel"], [data-reel], .reel-card, .reel-item').length;
      });

      const title = await page.title();
      const hasLazyLoad = await page.evaluate(() => typeof window._ivxLazyLoad === 'function');
      const hasReelsBtn = await page.evaluate(() => !!document.getElementById('ivxReelsBtn'));

      results.push({
        viewport: vp.name,
        width: vp.width,
        height: vp.height,
        title,
        scrollWidth,
        clientWidth,
        hasOverflow,
        sectionsVisible: sections,
        reelsCount,
        hasLazyLoad,
        hasReelsBtn,
        consoleErrors: errors.length,
        failedRequests: failedRequests.length,
        errorSamples: errors.slice(0, 3),
        failedRequestSamples: failedRequests.slice(0, 3),
      });
    } catch (err) {
      results.push({ viewport: vp.name, error: err.message });
    }
    await ctx.close();
  }

  await browser.close();
  console.log(JSON.stringify(results, null, 2));
}

run().catch(console.error);
